+fn append_backlog_payload(backlog: &mut Vec<u8>, payload: &[u8]) {
+    if payload.is_empty() {
+        return;
+    }
+
+    backlog.extend_from_slice(payload);
+    let max = max_backlog_bytes_per_pane();
+    if backlog.len() > max {
+        let excess = backlog.len() - max;
+        backlog.drain(..excess);
+    }
+}
